import React, { useState, useEffect } from "react";
import socket from "./socket";
import Lobby       from "./components/Lobby";
import WaitingRoom from "./components/WaitingRoom";
import GameScreen  from "./components/GameScreen";
import VoteScreen  from "./components/VoteScreen";
import RoundResult from "./components/RoundResult";
import GameOver    from "./components/GameOver";
import "./styles/main.css";

export default function App() {
  const [phase, setPhase]                   = useState("lobby");
  const [game, setGame]                     = useState(null);
  const [playerId, setPlayerId]             = useState(null);
  const [isHost, setIsHost]                 = useState(false);
  const [myRole, setMyRole]                 = useState(null);
  const [myWord, setMyWord]                 = useState(null);
  const [currentRound, setCurrentRound]     = useState(1);
  const [totalRounds, setTotalRounds]       = useState(3);
  const [descriptions, setDescriptions]     = useState([]);
  const [submittedCount, setSubmittedCount] = useState(0);
  const [votedCount, setVotedCount]         = useState(0);
  const [mySubmitted, setMySubmitted]       = useState(false);
  const [roundResultData, setRoundResultData] = useState(null);
  const [gameOverData, setGameOverData]       = useState(null);
  const [currentTurnId, setCurrentTurnId]     = useState(null);
  const [currentTurnName, setCurrentTurnName] = useState("");

  useEffect(() => {
    socket.on("lobbyUpdated", ({ game: g }) => {
      setGame(g);
    });

    socket.on("gameStarted", ({ role, word, round, totalRounds: tr, players, currentTurnId: tid, currentTurnName: tname }) => {
      setMyRole(role);
      setMyWord(word);
      setCurrentRound(round);
      setTotalRounds(tr);
      setMySubmitted(false);
      setSubmittedCount(0);
      setGame(g => ({ ...g, players }));
      // Set first turn
      if (tid) { setCurrentTurnId(tid); setCurrentTurnName(tname || ""); }
    });

    socket.on("phaseChanged", ({ phase: p, descriptions: descs, round, totalRounds: tr, currentTurnId: tid, currentTurnName: tname }) => {
      setPhase(p);
      if (descs)  setDescriptions(descs);
      if (round)  setCurrentRound(round);
      if (tr)     setTotalRounds(tr);
      if (tid)    { setCurrentTurnId(tid); setCurrentTurnName(tname || ""); }
      if (p === "describing") {
        setMySubmitted(false);
        setSubmittedCount(0);
        setVotedCount(0);
        setDescriptions([]);
      }
      if (p === "voting") setVotedCount(0);
    });

    socket.on("turnChanged", ({ currentTurnId: tid, currentTurnName: tname }) => {
      setCurrentTurnId(tid);
      setCurrentTurnName(tname || "");
    });

    socket.on("submissionUpdate", ({ submitted }) => setSubmittedCount(submitted));
    socket.on("voteUpdate",       ({ voted })     => setVotedCount(voted));

    socket.on("roundResult", ({ eliminatedName, wasImpostor, tally, round, players }) => {
      setRoundResultData({ eliminatedName, wasImpostor, tally, round });
      setGame(g => ({ ...g, players }));
      setPhase("roundResult");
    });

    socket.on("newRound", ({ role, word, round, totalRounds: tr, currentTurnId: tid, currentTurnName: tname }) => {
      setMyRole(role);
      setMyWord(word);
      setCurrentRound(round);
      setTotalRounds(tr);
      setMySubmitted(false);
      setSubmittedCount(0);
      setVotedCount(0);
      setDescriptions([]);
      if (tid) { setCurrentTurnId(tid); setCurrentTurnName(tname || ""); }
    });

    socket.on("gameOver", (data) => {
      setGameOverData(data);
      setGame(g => ({ ...g, players: data.players }));
      setPhase("gameOver");
    });

    return () => {
      socket.off("lobbyUpdated");
      socket.off("gameStarted");
      socket.off("phaseChanged");
      socket.off("turnChanged");
      socket.off("submissionUpdate");
      socket.off("voteUpdate");
      socket.off("roundResult");
      socket.off("newRound");
      socket.off("gameOver");
    };
  }, []);

  const handleJoined = ({ game: g, playerId: pid, isHost: host }) => {
    setGame(g);
    setPlayerId(pid);
    setIsHost(host);
    socket.emit("joinLobbyRoom", { lobbyCode: g.code, playerId: pid });
    setPhase("waiting");
  };

  const handleStartGame  = (rounds)   => socket.emit("startGame", { lobbyCode: game.code, totalRounds: rounds });
  const handleSubmitDesc = (text)     => { setMySubmitted(true); socket.emit("submitDescription", { lobbyCode: game.code, playerId, text }); };
  const handleVote       = (targetId) => socket.emit("castVote", { lobbyCode: game.code, voterId: playerId, targetId });

  const handlePlayAgain = () => {
    setPhase("lobby"); setGame(null); setPlayerId(null);
    setIsHost(false);  setMyRole(null); setMyWord(null);
    setRoundResultData(null); setGameOverData(null);
    setCurrentTurnId(null); setCurrentTurnName("");
  };

  if (phase === "lobby")
    return <Lobby onJoined={handleJoined} />;

  if (phase === "waiting")
    return <WaitingRoom game={game} playerId={playerId} isHost={isHost} onStartGame={handleStartGame} />;

  if (phase === "describing")
    return <GameScreen
      role={myRole} word={myWord} round={currentRound} totalRounds={totalRounds}
      players={game?.players || []} playerId={playerId}
      submitted={mySubmitted} submittedCount={submittedCount}
      totalCount={game?.players?.length || 0}
      currentTurnId={currentTurnId}
      currentTurnName={currentTurnName}
      onSubmit={handleSubmitDesc} />;

  if (phase === "voting")
    return <VoteScreen descriptions={descriptions} players={game?.players || []}
      playerId={playerId} votedCount={votedCount} totalCount={game?.players?.length || 0}
      round={currentRound} totalRounds={totalRounds} onVote={handleVote} />;

  if (phase === "roundResult")
    return <RoundResult eliminatedName={roundResultData?.eliminatedName}
      wasImpostor={roundResultData?.wasImpostor} tally={roundResultData?.tally}
      round={roundResultData?.round} players={game?.players || []} />;

  if (phase === "gameOver")
    return <GameOver impostorName={gameOverData?.impostorName}
      impostorCaught={gameOverData?.impostorCaught}
      players={game?.players || []} onPlayAgain={handlePlayAgain} />;

  return null;
}
